'use client';

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { getTelemetrySessionDetails, assignTelemetryPlayer, getDashboardData } from '@/lib/actions';
import { LoadingState, ErrorState } from '../../_components/StatusScreens';
import Link from 'next/link';

export default function SessionAssignmentPage() {
  const params = useParams();
  const router = useRouter();
  const leagueId = params.leagueId as string;
  const sessionId = params.sessionId as string;

  const [session, setSession] = useState<any>(null);
  const [participants, setParticipants] = useState<any[]>([]);
  const [drivers, setDrivers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, [leagueId, sessionId]);

  async function loadData() {
    setLoading(true);
    const [detailsRes, dashRes] = await Promise.all([
      getTelemetrySessionDetails(leagueId, sessionId),
      getDashboardData(leagueId)
    ]);

    if (detailsRes.success) {
      setSession(detailsRes.session);
      setParticipants(detailsRes.participants || []);
    }
    if (dashRes.success) {
      setDrivers(dashRes.standings || []);
    }

    if (!detailsRes.success) setError(detailsRes.error);
    setLoading(false);
  }

  const handleAssign = async (gameName: string, driverId: string | null) => {
    setSaving(gameName);
    try {
        const res = await assignTelemetryPlayer(leagueId, gameName, driverId || '');
        // Note: assignTelemetryPlayer currently expects strings, if we send null we might need to handle it or clear it in DB.
        // For now, let's assume valid selection is needed.
        if (res.success) {
            loadData();
        } else {
            alert('Error: ' + res.error);
        }
    } catch (e: any) {
        alert('Exception: ' + e.message);
    }
    setSaving(null);
  };

  if (loading) return <LoadingState />;
  if (error) return <ErrorState error={error} />;

  return (
    <div className="container" style={{ padding: '4rem 1.5rem', maxWidth: '1000px' }}>
      <header style={{ marginBottom: '3rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
            <Link href={`/profile/leagues/${leagueId}/telemetry`} className="btn-secondary btn-sm">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
                HUB
            </Link>
            <span className="text-f1" style={{ color: 'var(--f1-red)', fontSize: '0.8rem', letterSpacing: '2px' }}>SESSION MANAGEMENT</span>
        </div>
        <h1 className="text-f1 text-gradient" style={{ fontSize: '3rem' }}>DRIVER MAPPING</h1>
        <p style={{ color: 'var(--silver)' }}>Assign in-game names to official league participants for session #{sessionId.slice(0,8)}</p>
      </header>

      <div className="f1-card p-0 overflow-hidden">
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: 'rgba(255,255,255,0.05)', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>POS</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>IN-GAME NAME (TELEMETRY)</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>ASSIGNED LEAGUE DRIVER</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'right', fontSize: '0.7rem' }}>BEST LAP</th>
            </tr>
          </thead>
          <tbody>
            {participants.map((p) => {
              const isAssigned = !!p.driver_id;
              return (
                <tr key={p.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)', transition: 'background 0.2s' }}>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="text-f1" style={{ fontSize: '1.2rem', opacity: 0.5 }}>{p.position}</div>
                  </td>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="flex flex-col">
                        <span className="text-f1" style={{ color: p.is_human ? 'var(--f1-red)' : 'var(--silver)' }}>{p.gameName}</span>
                        {!p.is_human && <span style={{ fontSize: '0.6rem', color: 'var(--silver)', opacity: 0.4 }}>AI CONSTRUCT</span>}
                    </div>
                  </td>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="flex items-center gap-2">
                        <select 
                            className="glass-input"
                            style={{ padding: '5px 10px', fontSize: '0.8rem', width: '200px' }}
                            value={p.driver_id || ''}
                            onChange={(e) => handleAssign(p.gameName, e.target.value)}
                            disabled={saving === p.gameName}
                        >
                            <option value="">- Select Driver -</option>
                            {drivers.map(d => (
                                <option key={d.id} value={d.id}>{d.name}</option>
                            ))}
                        </select>
                        {saving === p.gameName && <span className="animate-pulse" style={{ fontSize: '0.8rem' }}>SYNCING...</span>}
                        {isAssigned && <span style={{ color: 'var(--f1-green)' }}>✅</span>}
                    </div>
                  </td>
                  <td style={{ padding: '15px 20px', textAlign: 'right' }}>
                    <div className="text-mono" style={{ fontSize: '0.8rem' }}>
                        {p.fastest_lap_ms ? `${(p.fastest_lap_ms / 1000).toFixed(3)}s` : '--:--:---'}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

        <div className="mt-8 flex justify-end gap-small">
            <Link href={`/profile/analysis/${sessionId}`} className="btn-secondary btn-sm" style={{ padding: '12px 24px' }}>
                OPEN DEEP DIVE
            </Link>
        </div>
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { getTelemetrySessionDetails, assignTelemetryPlayer, getDashboardData, promoteTelemetryToRace } from '@/lib/actions';
import { LoadingState, ErrorState } from '../../_components/StatusScreens';
import Link from 'next/link';

export default function SessionAssignmentPage() {
  const params = useParams();
  const router = useRouter();
  const leagueId = params.leagueId as string;
  const sessionId = params.sessionId as string;

  const [session, setSession] = useState<any>(null);
  const [participants, setParticipants] = useState<any[]>([]);
  const [drivers, setDrivers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState<string | null>(null);
  const [promoting, setPromoting] = useState(false);

  useEffect(() => {
    loadData();
  }, [leagueId, sessionId]);

  async function loadData() {
    setLoading(true);
    const [detailsRes, dashRes] = await Promise.all([
      getTelemetrySessionDetails(leagueId, sessionId),
      getDashboardData(leagueId)
    ]);

    if (detailsRes.success) {
      setSession(detailsRes.session);
      setParticipants(detailsRes.participants || []);
    }
    if (dashRes.success) {
      setDrivers(dashRes.standings || []);
    }

    if (!detailsRes.success) setError(detailsRes.error);
    setLoading(false);
  }

   const handleAssign = async (gameName: string, driverId: string | null) => {
     setSaving(gameName);
     try {
         const res = await assignTelemetryPlayer(leagueId, gameName, driverId || '');
         // Note: assignTelemetryPlayer currently expects strings, if we send null we might need to handle it or clear it in DB.
         // For now, let's assume valid selection is needed.
         if (res.success) {
             loadData();
         } else {
             alert('Error: ' + res.error);
         }
     } catch (e: any) {
         alert('Exception: ' + e.message);
     }
     setSaving(null);
   };

   const handlePromoteToRace = async () => {
     const assignedCount = participants.filter((p: any) => p.driver_id).length;
     if (assignedCount === 0) {
       alert('You must assign at least one driver before finishing the session.');
       return;
     }

     const trackName = session?.track_id ? `Track ${session.track_id}` : 'Unknown Track';
     if (!confirm(`Are you sure you want to finalize this session as a race result? This will:\n\n✓ Create official race results\n✓ Assign ${assignedCount} driver(s)\n✓ Calculate points\n\nTrack: ${trackName}`)) {
       return;
     }

     setPromoting(true);
     try {
       const res = await promoteTelemetryToRace(leagueId, sessionId, trackName);
       if (res.success) {
         alert('Session promoted to race result successfully!');
         router.push(`/profile/leagues/${leagueId}`);
       } else {
         alert('Error: ' + res.error);
       }
     } catch (e: any) {
       alert('Exception: ' + e.message);
     } finally {
       setPromoting(false);
     }
   };

  if (loading) return <LoadingState />;
  if (error) return <ErrorState error={error} />;

  return (
    <div className="container" style={{ padding: '4rem 1.5rem', maxWidth: '1000px' }}>
      <header style={{ marginBottom: '3rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
            <Link href={`/profile/leagues/${leagueId}/telemetry`} className="btn-secondary btn-sm">
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
                HUB
            </Link>
            <span className="text-f1" style={{ color: 'var(--f1-red)', fontSize: '0.8rem', letterSpacing: '2px' }}>SESSION MANAGEMENT</span>
        </div>
        <h1 className="text-f1 text-gradient" style={{ fontSize: '3rem' }}>DRIVER MAPPING</h1>
        <p style={{ color: 'var(--silver)' }}>Assign in-game names to official league participants for session #{sessionId.slice(0,8)}</p>
      </header>

      <div className="f1-card p-0 overflow-hidden">
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: 'rgba(255,255,255,0.05)', borderBottom: '1px solid rgba(255,255,255,0.1)' }}>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>POS</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>IN-GAME NAME (TELEMETRY)</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'left', fontSize: '0.7rem' }}>ASSIGNED LEAGUE DRIVER</th>
              <th className="text-f1" style={{ padding: '15px 20px', textAlign: 'right', fontSize: '0.7rem' }}>BEST LAP</th>
            </tr>
          </thead>
          <tbody>
            {participants.map((p) => {
              const isAssigned = !!p.driver_id;
              return (
                <tr key={p.id} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)', transition: 'background 0.2s' }}>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="text-f1" style={{ fontSize: '1.2rem', opacity: 0.5 }}>{p.position}</div>
                  </td>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="flex flex-col">
                        <span className="text-f1" style={{ color: p.is_human ? 'var(--f1-red)' : 'var(--silver)' }}>{p.gameName}</span>
                        {!p.is_human && <span style={{ fontSize: '0.6rem', color: 'var(--silver)', opacity: 0.4 }}>AI CONSTRUCT</span>}
                    </div>
                  </td>
                  <td style={{ padding: '15px 20px' }}>
                    <div className="flex items-center gap-2">
                        <select 
                            className="glass-input"
                            style={{ padding: '5px 10px', fontSize: '0.8rem', width: '200px' }}
                            value={p.driver_id || ''}
                            onChange={(e) => handleAssign(p.gameName, e.target.value)}
                            disabled={saving === p.gameName}
                        >
                            <option value="">- Select Driver -</option>
                            {drivers.map(d => (
                                <option key={d.id} value={d.id}>{d.name}</option>
                            ))}
                        </select>
                        {saving === p.gameName && <span className="animate-pulse" style={{ fontSize: '0.8rem' }}>SYNCING...</span>}
                        {isAssigned && <span style={{ color: 'var(--f1-green)' }}>✅</span>}
                    </div>
                  </td>
                  <td style={{ padding: '15px 20px', textAlign: 'right' }}>
                    <div className="text-mono" style={{ fontSize: '0.8rem' }}>
                        {p.fastest_lap_ms ? `${(p.fastest_lap_ms / 1000).toFixed(3)}s` : '--:--:---'}
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
       </div>

         <div className="mt-8 flex justify-between gap-small">
             <div className="flex gap-small">
                 <Link href={`/profile/leagues/${leagueId}/telemetry`} className="btn-secondary btn-sm" style={{ padding: '12px 24px' }}>
                     BACK TO HUB
                 </Link>
             </div>
             <div className="flex gap-small">
                 <Link href={`/profile/analysis/${sessionId}`} className="btn-secondary btn-sm" style={{ padding: '12px 24px' }}>
                     OPEN DEEP DIVE
                 </Link>
                 <button 
                     className="btn-primary btn-sm" 
                     onClick={handlePromoteToRace}
                     disabled={promoting}
                     style={{ padding: '12px 24px', background: promoting ? 'rgba(255,24,1,0.3)' : 'var(--f1-red)' }}
                 >
                     {promoting ? '⏳ FINALIZING...' : '✓ FINISH SESSION'}
                 </button>
             </div>
         </div>
     </div>
   );
}

'use server';

import * as crypto from 'node:crypto';
import bcrypt from "bcryptjs";
import { query, run } from './db';

import { getServerSession } from "next-auth/next";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";

async function verifyLeagueOwner(leagueId: string) {
    const session = await getServerSession(authOptions) as any;
    if (!session || !session.user || !session.user.id) {
        console.log('DEBUG: No session or no user.id', { sessionUser: session?.user });
        throw new Error('Unauthorized session.');
    }
    const res = await query<any>('SELECT owner_id FROM leagues WHERE id = ?', [leagueId]);
    console.log('DEBUG: verifyLeagueOwner', { 
        leagueId, 
        dbOwner: res[0]?.owner_id, 
        sessionUserId: session.user.id,
        match: res[0]?.owner_id == session.user.id
    });
    if (res.length === 0 || String(res[0].owner_id) !== String(session.user.id)) throw new Error('Unauthorized. Not the owner.');
}

import { calculatePoints, DEFAULT_CONFIG, PointsConfig } from './scoring';

/**
 * Adds a driver to a league as an admin.
 */
export async function adminAddDriver(leagueId: string, driverName: string, team: string, color: string, gameName?: string) {
    try {
        await verifyLeagueOwner(leagueId);

        const driverId = crypto.randomUUID();

        await run(
            `INSERT INTO drivers (id, league_id, name, team, color, game_name, team_id) VALUES (?, ?, ?, ?, ?, ?, ?)`,
            [driverId, leagueId, driverName, team, color || '#ffffff', gameName || null, null]
        );

        return { success: true };
    } catch (error: any) {
        console.error('Admin Add Driver Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Saves race results. If raceId is provided, it updates a scheduled race.
 */
export async function saveRaceResults(leagueId: string, track: string, results: any[], existingRaceId?: string) {
    try {
        // 1. Fetch Points Config
        const configRes = await getPointsConfig(leagueId);
        const config = configRes.success ? configRes.config : DEFAULT_CONFIG;

        let raceId = existingRaceId;

        // 2. Auto-Link if no ID provided
        if (!raceId) {
            const scheduled = await query<any>(
                `SELECT id FROM races WHERE league_id = ? AND track = ? AND is_finished = false ORDER BY scheduled_date ASC LIMIT 1`,
                [leagueId, track]
            );
            if (scheduled.length > 0) {
                raceId = scheduled[0].id;
                console.log(`Auto-linked to scheduled race: ${raceId}`);
            }
        }

        // 3. Create Race if not exists
        if (!raceId) {
            raceId = crypto.randomUUID();
            await run(
                `INSERT INTO races (id, league_id, track, is_finished, race_date) VALUES (?, ?, ?, true, CURRENT_TIMESTAMP)`,
                [raceId, leagueId, track]
            );
            console.log(`Race created: ${track} (${raceId})`);
        } else {
            // Update scheduled race to finished
            await run(
                `UPDATE races SET is_finished = true, race_date = CURRENT_TIMESTAMP WHERE id = ?`,
                [raceId]
            );
            console.log(`Race finished: ${track} (${raceId})`);
        }

        // 3. Insert Results
        for (const res of results) {
            const points = calculatePoints({
                position: res.position,
                qualiPosition: res.quali_position ? parseInt(res.quali_position as any) : undefined,
                fastestLap: res.fastest_lap,
                cleanDriver: res.clean_driver,
                isDnf: res.is_dnf
            }, config);

            const resultId = crypto.randomUUID();
            await run(
                `INSERT INTO race_results (id, race_id, driver_id, position, quali_position, fastest_lap, clean_driver, points_earned, is_dnf, pit_stops, warnings, penalties_time)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [resultId, raceId, res.driver_id, res.position, res.quali_position || 0, !!res.fastest_lap, !!res.clean_driver, points, !!res.is_dnf, res.pit_stops || 0, res.warnings || 0, res.penalties_time || 0]
            );
        }

        // 4. Recalculate Standings
        await recalculateStandings(leagueId);

        return { success: true, raceId };
    } catch (error: any) {
        console.error('Save Results Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Recalculates all driver totals for a league, accounting for drop results.
 * Optimized with Batch-Loading to avoid N+1 queries.
 */
export async function recalculateStandings(leagueId: string) {
    const drivers = await query<any>(`SELECT id FROM drivers WHERE league_id = ?`, [leagueId]);
    const configRes = await getPointsConfig(leagueId);
    const config = configRes.success ? configRes.config : DEFAULT_CONFIG;

    // Total finished races in this league
    const racesCountRes = await query<any>(`SELECT COUNT(*) as c FROM races WHERE league_id = ? AND is_finished = true`, [leagueId]);
    const finishedRacesCount = parseInt(racesCountRes[0].c || 0);

    // Max drops calculation
    const referenceRaces = (config?.totalRaces && config.totalRaces > 0) ? config.totalRaces : finishedRacesCount;
    const maxDropsAllowed = Math.floor(referenceRaces * 0.25);
    const actualDrops = Math.min((config?.dropResultsCount || 0), maxDropsAllowed);

    // BATCH-LOADING: Fetch ALL results for ALL drivers in this league at once
    const allResults = await query<any>(`
        SELECT rr.id, rr.driver_id, rr.points_earned 
        FROM race_results rr
        JOIN races r ON rr.race_id = r.id
        WHERE r.league_id = ? AND r.is_finished = true
    `, [leagueId]);

    // Group results by driver_id for O(1) access
    const resultsMap = new Map<string, { id: string; points: number }[]>();
    allResults.forEach((r: any) => {
        if (!resultsMap.has(r.driver_id)) resultsMap.set(r.driver_id, []);
        resultsMap.get(r.driver_id)!.push({ id: r.id, points: r.points_earned || 0 });
    });

    for (const driver of drivers) {
        const driverResults = resultsMap.get(driver.id) || [];

        let allPoints: { id: string | null; points: number }[] = driverResults.map((r: any) => ({
            id: r.id,
            points: r.points
        }));

        // Fill missed races with 0s
        while (allPoints.length < finishedRacesCount) {
            allPoints.push({ id: null, points: 0 });
        }

        const rawPoints = allPoints.reduce((sum, p) => sum + p.points, 0);

        // Sort ascending to identify lowest results to drop
        const sortedPoints = [...allPoints].sort((a, b) => a.points - b.points);
        let totalPoints = rawPoints;
        let droppedResultIds: string[] = [];

        if (actualDrops > 0 && sortedPoints.length >= actualDrops) {
            const dropped = sortedPoints.slice(0, actualDrops);
            const droppedPointsSum = dropped.reduce((sum, p) => sum + p.points, 0);
            totalPoints -= droppedPointsSum;
            droppedResultIds = dropped.filter(d => d.id !== null).map(d => d.id as string);
        }

        // Update driver totals
        await run(`UPDATE drivers SET total_points = ?, raw_points = ? WHERE id = ?`, [totalPoints, rawPoints, driver.id]);

        // Reset dropped flags first (for this driver)
        await run(`UPDATE race_results SET is_dropped = false WHERE driver_id = ?`, [driver.id]);

        // Mark current drops
        if (droppedResultIds.length > 0) {
            const placeholders = droppedResultIds.map(() => '?').join(',');
            await run(`UPDATE race_results SET is_dropped = true WHERE id IN (${placeholders})`, droppedResultIds);
        }
    }
}

/**
 * Schedules a future race.
 */
export async function scheduleRace(leagueId: string, track: string, date: string, isRandom = false, revealHours = 0) {
    try {
        // Auth Check
        await verifyLeagueOwner(leagueId);

        let finalTrack = track;
        if (isRandom) {
            // Get track pool from config
            const configRow = await query<any>(`SELECT track_pool FROM points_config WHERE league_id = ?`, [leagueId]);
            let pool = [];
            try {
                if (configRow.length > 0 && configRow[0].track_pool) {
                    pool = JSON.parse(configRow[0].track_pool);
                }
            } catch (e) {}

            if (pool.length === 0) {
                const { F1_TRACKS_2025 } = require('./constants');
                pool = F1_TRACKS_2025;
            }

            // Also exclude already used tracks if possible
            const usedTracks = await query<any>(`SELECT track FROM races WHERE league_id = ?`, [leagueId]);
            const usedSet = new Set(usedTracks.map((r: any) => r.track));
            const available = pool.filter((t: any) => !usedSet.has(t));

            const selectionPool = available.length > 0 ? available : pool;
            finalTrack = selectionPool[Math.floor(Math.random() * selectionPool.length)];
        }

        const raceId = crypto.randomUUID();
        await run(
            `INSERT INTO races (id, league_id, track, is_finished, scheduled_date, is_random, reveal_hours_before) VALUES (?, ?, ?, false, ?, ?, ?)`,
            [raceId, leagueId, finalTrack, date, isRandom, revealHours]
        );
        return { success: true };
    } catch (error: any) {
        console.error('Schedule Race Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Fetches dashboard data including detailed statistics.
 */
export async function getDashboardData(leagueName: string) {
    try {
        // Check if leagueName is actually a UUID
        const isUuid = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(leagueName);
        let leagues;
        if (isUuid) {
            leagues = await query<any>(`SELECT id, name FROM leagues WHERE id = ?`, [leagueName]);
        } else {
            leagues = await query<any>(`SELECT id, name FROM leagues WHERE name = ?`, [leagueName]);
        }

        if (leagues.length === 0) throw new Error('League not found.');
        const leagueId = leagues[0].id;

        const standings = await query<any>(`
            SELECT d.*, u.avatar_url,
                COUNT(CASE WHEN rr.position = 1 AND r.is_finished = true THEN 1 END) as wins,
                COUNT(CASE WHEN rr.position <= 3 AND rr.position > 0 AND r.is_finished = true THEN 1 END) as podiums,
                COUNT(CASE WHEN rr.fastest_lap = true AND r.is_finished = true THEN 1 END) as fastest_laps,
                COUNT(CASE WHEN rr.clean_driver = true AND r.is_finished = true THEN 1 END) as clean_races
            FROM drivers d 
            LEFT JOIN users u ON d.user_id = u.id
            LEFT JOIN race_results rr ON d.id = rr.driver_id
            LEFT JOIN races r ON rr.race_id = r.id
            WHERE d.league_id = ? 
            GROUP BY d.id, u.id
            ORDER BY d.total_points DESC, wins DESC, podiums DESC
        `, [leagueId]);

        const finishedRaces = await query<any>(
            `SELECT * FROM races WHERE league_id = ? AND is_finished = true ORDER BY race_date ASC`,
            [leagueId]
        );

        const upcomingRacesRaw = await query<any>(
            `SELECT * FROM races WHERE league_id = ? AND is_finished = false ORDER BY scheduled_date ASC`,
            [leagueId]
        );

        const now = new Date();
        const upcomingRaces = upcomingRacesRaw.map((r: any) => {
            if (r.is_random && r.reveal_hours_before > 0) {
                const revealDate = new Date(new Date(r.scheduled_date).getTime() - r.reveal_hours_before * 60 * 60 * 1000);
                if (now < revealDate) {
                    return { ...r, track: '?? (Hidden)', is_hidden: true };
                }
            }
            return { ...r, is_hidden: false };
        });

        const teams = await query<any>(`SELECT * FROM teams WHERE league_id = ?`, [leagueId]);

        // Build Chronological Data for the Graph and Form Indicator
        // 1. Fetch all results for finished races in this league
        const allResults = await query<any>(`
            SELECT rr.race_id, rr.driver_id, rr.points_earned
            FROM race_results rr
            JOIN races r ON rr.race_id = r.id
            WHERE r.league_id = ? AND r.is_finished = true
            ORDER BY r.race_date ASC
        `, [leagueId]);

        // Map results by driver_id and race_id
        const resultsByRace: Record<string, Record<string, number>> = {};
        allResults.forEach((res: any) => {
            if (!resultsByRace[res.race_id]) resultsByRace[res.race_id] = {};
            resultsByRace[res.race_id][res.driver_id] = res.points_earned;
        });

        const graphData: any[] = [];
        const runningTotals: Record<string, number> = {};
        const teamRunningTotals: Record<string, number> = {};
        const previousPoints: Record<string, number> = {}; // Points from race N-1
        const latestPoints: Record<string, number> = {};   // Points from race N

        standings.forEach((d: any) => {
            runningTotals[d.id] = 0;
            d.formIndicator = 'SAME'; // Default
        });

        teams.forEach((t: any) => {
            teamRunningTotals[t.id] = 0;
        });

        const teamGraphData: any[] = [];

        // Calculate running totals per race for the graph
        finishedRaces.forEach((race: any, index: number) => {
            const dataPoint: any = { name: race.track || `Race ${index + 1}` };

            standings.forEach((d: any) => {
                const earned = resultsByRace[race.id]?.[d.id] || 0;

                // Track for form indicator later
                if (index === finishedRaces.length - 2) {
                    previousPoints[d.id] = earned;
                }
                if (index === finishedRaces.length - 1) {
                    latestPoints[d.id] = earned;
                }

                runningTotals[d.id] += earned;
                dataPoint[d.name] = runningTotals[d.id];

                // Add to team total if assigned
                if (d.team_id && teamRunningTotals[d.team_id] !== undefined) {
                    teamRunningTotals[d.team_id] += earned;
                }
            });

            graphData.push(dataPoint);

            // Build separate team graph point for this same race
            const teamDataPoint: any = { name: race.track || `Race ${index + 1}` };
            teams.forEach((t: any) => {
                teamDataPoint[t.name] = teamRunningTotals[t.id];
            });
            teamGraphData.push(teamDataPoint);
        });

        // Determine Form Indicator
        if (finishedRaces.length >= 2) {
            standings.forEach((d: any) => {
                const prev = previousPoints[d.id] || 0;
                const curr = latestPoints[d.id] || 0;
                if (curr > prev) d.formIndicator = 'UP';
                else if (curr < prev) d.formIndicator = 'DOWN';
                else d.formIndicator = 'SAME';
            });
        } else if (finishedRaces.length === 1) {
            standings.forEach((d: any) => {
                const curr = latestPoints[d.id] || 0;
                if (curr > 0) d.formIndicator = 'UP';
                else d.formIndicator = 'SAME';
            });
        }

        const totalRaces = await query<any>(`SELECT COUNT(*) as count FROM races WHERE league_id = ? AND is_finished = true`, [leagueId]);

        const configRes = await getPointsConfig(leagueId);
        const config = configRes.success ? configRes.config : DEFAULT_CONFIG;

        // Calculate remaining tracks from the pool
        let remainingTracks: string[] = [];
        if (config?.trackPool && config.trackPool.length > 0) {
            const usedTracks = new Set([...finishedRaces, ...upcomingRaces].map((r: any) => r.track));
            remainingTracks = config.trackPool.filter(t => !usedTracks.has(t));
        }

        // Calculate max actual drops allowed
        const referenceRaces = (config?.totalRaces && config.totalRaces > 0) ? config.totalRaces : finishedRaces.length;
        const maxDropsAllowed = Math.floor(referenceRaces * 0.25);
        const actualDrops = Math.min((config?.dropResultsCount || 0), maxDropsAllowed);

        // Team Standings
        let teamStandings = [];
        if (config && config.teamCompetition) {
            teamStandings = await query<any>(`
                SELECT t.id, t.name, t.color,
                    (SELECT COALESCE(SUM(d.total_points), 0) FROM drivers d WHERE d.team_id = t.id) as total_points,
                    (SELECT COALESCE(SUM(d.raw_points), 0) FROM drivers d WHERE d.team_id = t.id) as raw_points,
                    (SELECT COUNT(*) FROM race_results rr JOIN drivers dr ON rr.driver_id = dr.id WHERE dr.team_id = t.id AND rr.position = 1) as wins,
                    (SELECT COUNT(*) FROM race_results rr JOIN drivers dr ON rr.driver_id = dr.id WHERE dr.team_id = t.id AND rr.position <= 3) as podiums
                FROM teams t
                WHERE t.league_id = ?
                ORDER BY total_points DESC, wins DESC
            `, [leagueId]);
        }

        return {
            success: true,
            league: { ...leagues[0], config },
            standings,
            teamStandings,
            races: finishedRaces.slice().reverse().slice(0, 10), // Keep recent races descending
            upcoming: upcomingRaces,
            graphData,
            teamGraphData,
            stats: {
                totalRaces: totalRaces[0].count,
                plannedTotalRaces: config?.totalRaces || 0,
                remainingTracks,
                actualDrops,
                maxDropsAllowed
            },
            config
        };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

