/**
 * Updates points configuration for a league.
 */
export async function updatePointsConfig(leagueId: string, config: PointsConfig) {
    try {
        // Auth Check
        await verifyLeagueOwner(leagueId);

        // Check if config exists
        const existingConfig = await query<any>(`SELECT league_id FROM points_config WHERE league_id = ?`, [leagueId]);

        if (existingConfig.length > 0) {
            await run(
                `UPDATE points_config SET 
                    points_json = ?, 
                    quali_points_json = ?,
                    fastest_lap_bonus = ?, 
                    clean_driver_bonus = ?,
                    total_races = ?,
                    track_pool = ?,
                    drop_results_count = ?,
                    team_competition = ?
                 WHERE league_id = ?`,
                [JSON.stringify(config.points), JSON.stringify(config.qualiPoints || {}), config.fastestLapBonus, config.cleanDriverBonus, config.totalRaces || 0, JSON.stringify(config.trackPool || []), config.dropResultsCount || 0, config.teamCompetition ? 1 : 0, leagueId]
            );
        } else {
            await run(
                `INSERT INTO points_config (league_id, points_json, quali_points_json, fastest_lap_bonus, clean_driver_bonus, total_races, track_pool, drop_results_count, team_competition)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [leagueId, JSON.stringify(config.points), JSON.stringify(config.qualiPoints || {}), config.fastestLapBonus, config.cleanDriverBonus, config.totalRaces || 0, JSON.stringify(config.trackPool || []), config.dropResultsCount || 0, config.teamCompetition ? 1 : 0]
            );
        }

        // Recalculate standings since point rules might have changed
        await recalculateStandings(leagueId);

        return { success: true };
    } catch (error: any) {
        console.error('Update Points Config Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Updates results for an existing race.
 */
export async function updateRaceResults(leagueId: string, raceId: string, results: any[]) {
    try {
        // 1. Auth Check
        await verifyLeagueOwner(leagueId);

        // 2. Fetch Points Config
        const configRes = await getPointsConfig(leagueId);
        const config = configRes.success ? configRes.config : DEFAULT_CONFIG;

        // 3. Delete existing results for this race
        await run(`DELETE FROM race_results WHERE race_id = ?`, [raceId]);

        // 4. Insert new (updated) results
        for (const res of results) {
            const points = calculatePoints({
                position: parseInt(res.position as any),
                qualiPosition: res.quali_position ? parseInt(res.quali_position as any) : undefined,
                fastestLap: !!res.fastest_lap,
                cleanDriver: !!res.clean_driver,
                isDnf: !!res.is_dnf
            }, config);

            const resultId = crypto.randomUUID();
            await run(
                `INSERT INTO race_results (id, race_id, driver_id, position, quali_position, fastest_lap, clean_driver, points_earned, is_dnf, pit_stops, warnings, penalties_time)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [resultId, raceId, res.driver_id, res.position, res.quali_position || 0, !!res.fastest_lap, !!res.clean_driver, points, !!res.is_dnf, res.pit_stops || 0, res.warnings || 0, res.penalties_time || 0]
            );
        }

        // 5. Recalculate Standings
        await recalculateStandings(leagueId);

        return { success: true };
    } catch (error: any) {
        console.error('Update Results Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Checks for an active telemetry session for a specific league.
 */
export async function getActiveTelemetrySession(leagueId: string) {
    try {
        const active = await query<any>(
            `SELECT * FROM telemetry_sessions 
             WHERE league_id = ? 
             AND is_active = true 
             AND updated_at > NOW() - INTERVAL '2 minutes'
             ORDER BY created_at DESC LIMIT 1`,
            [leagueId]
        );
        if (active.length > 0) {
            // Also fetch participants and join with drivers for color
            const participants = await query<any>(
                `SELECT tp.*, d.color 
                 FROM telemetry_participants tp
                 LEFT JOIN drivers d ON tp.driver_id = d.id
                 WHERE tp.session_id = ? 
                 ORDER BY tp.position ASC`,
                [active[0].id]
            );
            return { success: true, session: active[0], participants };
        }
        return { success: true, session: null, participants: [] };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Fetches all unassigned players from recent telemetry sessions.
 * Requires admin.
 */
export async function getUnassignedTelemetryPlayers(leagueId: string) {
    try {
        await verifyLeagueOwner(leagueId);

        const unassigned = await query<any>(`
            SELECT tp.game_name, tp.session_id, ts.created_at
            FROM telemetry_participants tp
            JOIN telemetry_sessions ts ON tp.session_id = ts.id
            WHERE ts.league_id = ? AND tp.driver_id IS NULL AND tp.is_human = true
            GROUP BY tp.game_name, tp.session_id, ts.created_at
            ORDER BY ts.created_at DESC
        `, [leagueId]);

        return { success: true, unassigned };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Assigns a driver ID to a game_name for a specific session.
 * We could also broadly update ALL sessions. Doing all where it's null.
 * ALso saves it to the drivers table so future sessions map automatically.
 */
export async function assignTelemetryPlayer(leagueId: string, gameName: string, driverId: string) {
    try {
        await verifyLeagueOwner(leagueId);

        // Validate inputs
        if (!gameName || (!driverId && driverId !== '')) {
            throw new Error('Invalid game name or driver ID.');
        }

        // Handle unassignment (empty driver ID)
        if (!driverId) {
            await run(
                `UPDATE telemetry_participants SET driver_id = NULL WHERE session_id IN (
                    SELECT id FROM telemetry_sessions WHERE league_id = ?
                ) AND game_name = ?`,
                [leagueId, gameName]
            );
            return { success: true };
        }

        // Validate driver exists in league
        const driverCheck = await query<any>(
            `SELECT id FROM drivers WHERE id = ? AND league_id = ?`,
            [driverId, leagueId]
        );
        if (driverCheck.length === 0) {
            throw new Error('Driver not found in this league.');
        }

        // Assign driver to participant
        await run(
            `UPDATE telemetry_participants SET driver_id = ? WHERE session_id IN (
                SELECT id FROM telemetry_sessions WHERE league_id = ?
            ) AND game_name = ?`,
            [driverId, leagueId, gameName]
        );

        return { success: true };
    } catch (error: any) {
        console.error('assignTelemetryPlayer Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Promotes a telemetry session to official race results.
 */
export async function promoteTelemetryToRace(leagueId: string, sessionId: string, trackName: string) {
    try {
        await verifyLeagueOwner(leagueId);

        // Get session info
        const sessions = await query<any>(
            `SELECT * FROM telemetry_sessions WHERE id = ? AND league_id = ?`,
            [sessionId, leagueId]
        );
        if (sessions.length === 0) {
            throw new Error('Session not found or not in this league.');
        }

        const session = sessions[0];
        const trackId = session.track_id;

        // Get all assigned participants with their best lap times
        const participants = await query<any>(`
            SELECT tp.id, tp.game_name, tp.driver_id, tp.position,
                   (SELECT MIN(lap_time_ms) FROM telemetry_laps tl 
                    WHERE tl.participant_id = tp.id AND tl.is_valid = true) as best_lap_ms,
                   (SELECT COUNT(*) FROM telemetry_laps tl 
                    WHERE tl.participant_id = tp.id) as lap_count,
                   tp.pit_stops, tp.penalties_time, tp.total_race_time
            FROM telemetry_participants tp
            WHERE tp.session_id = ? AND tp.driver_id IS NOT NULL
            ORDER BY tp.position ASC
        `, [sessionId]);

        if (participants.length === 0) {
            throw new Error('No drivers assigned to this session.');
        }

        // Fetch points configuration
        const configRes = await getPointsConfig(leagueId);
        const config = configRes.success ? configRes.config : DEFAULT_CONFIG;

        // Create or update race
        const existingRace = await query<any>(
            `SELECT id FROM races WHERE league_id = ? AND track = ? AND is_finished = false ORDER BY scheduled_date ASC LIMIT 1`,
            [leagueId, trackName]
        );

        let raceId = existingRace.length > 0 ? existingRace[0].id : crypto.randomUUID();

        if (existingRace.length === 0) {
            await run(
                `INSERT INTO races (id, league_id, track, is_finished, race_date) VALUES (?, ?, ?, true, CURRENT_TIMESTAMP)`,
                [raceId, leagueId, trackName]
            );
        } else {
            await run(
                `UPDATE races SET is_finished = true, race_date = CURRENT_TIMESTAMP WHERE id = ?`,
                [raceId]
            );
        }

        // Insert race results for each driver
        for (const p of participants) {
            const points = calculatePoints({
                position: p.position,
                fastestLap: false, // Can be enhanced if tracking fastest lap per session
                cleanDriver: true, // Assume clean by default
                isDnf: (p.lap_count || 0) === 0
            }, config);

            const resultId = crypto.randomUUID();
            await run(
                `INSERT INTO race_results (id, race_id, driver_id, position, points_earned, fastest_lap, clean_driver, is_dnf)
                 VALUES (?, ?, ?, ?, ?, false, true, ?)`,
                [resultId, raceId, p.driver_id, p.position, points, (p.lap_count || 0) === 0]
            );

            // Update driver's total points
            await run(
                `UPDATE drivers SET total_points = total_points + ? WHERE id = ?`,
                [points, p.driver_id]
            );
        }

        // Link session to race
        await run(
            `UPDATE telemetry_sessions SET race_id = ?, is_active = false WHERE id = ?`,
            [raceId, sessionId]
        );

        return { success: true, raceId };
    } catch (error: any) {
        console.error('promoteTelemetryToRace Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Internal function to promote telemetry automatically (called from API worker).
 */
export async function internalPromoteTelemetryToRace(leagueId: string, sessionId: string, trackName: string) {
    try {
        // Skip owner verification for internal use
        const sessions = await query<any>(
            `SELECT * FROM telemetry_sessions WHERE id = ? AND league_id = ?`,
            [sessionId, leagueId]
        );
        if (sessions.length === 0) {
            console.log('Session not found, skipping auto-promote');
            return { success: false, error: 'Session not found' };
        }

        // Only promote if there are assigned drivers
        const assignedCount = await query<any>(
            `SELECT COUNT(*) as cnt FROM telemetry_participants WHERE session_id = ? AND driver_id IS NOT NULL`,
            [sessionId]
        );

        if ((assignedCount[0]?.cnt || 0) === 0) {
            console.log('No assigned drivers, skipping auto-promote');
            return { success: false, error: 'No assigned drivers' };
        }

        // Delegate to main function
        return await promoteTelemetryToRace(leagueId, sessionId, trackName);
    } catch (error: any) {
        console.error('internalPromoteTelemetryToRace Error:', error);
        return { success: false, error: error.message };
    }
}

/**
 * Fetches all telemetry sessions for a league.
 */
export async function getAllTelemetrySessions(leagueId: string) {
    try {
        await verifyLeagueOwner(leagueId);

        const sessions = await query<any>(`SELECT * FROM telemetry_sessions WHERE league_id = ? ORDER BY created_at DESC`, [leagueId]);

        // Count participants
        const participantsCount = await query<any>(`
            SELECT session_id, COUNT(*) as count 
            FROM telemetry_participants 
            WHERE session_id IN (SELECT id FROM telemetry_sessions WHERE league_id = ?)
            GROUP BY session_id
        `, [leagueId]);

        const countMap = new Map();
        participantsCount.forEach((p: any) => countMap.set(p.session_id, p.count));

        return {
            success: true,
            sessions: sessions.map((s: any) => ({ ...s, participants_count: countMap.get(s.id) || 0 }))
        };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Deletes a telemetry session.
 */
export async function deleteTelemetrySession(sessionId: string, leagueId: string) {
    try {
        await verifyLeagueOwner(leagueId);

        await run(`DELETE FROM telemetry_safety_car_events WHERE session_id = ?`, [sessionId]);
        await run(`DELETE FROM telemetry_position_history WHERE session_id = ?`, [sessionId]);
        await run(`DELETE FROM telemetry_laps WHERE participant_id IN (SELECT id FROM telemetry_participants WHERE session_id = ?)`, [sessionId]);
        await run(`DELETE FROM telemetry_participants WHERE session_id = ?`, [sessionId]);
        await run(`DELETE FROM telemetry_sessions WHERE id = ? AND league_id = ?`, [sessionId, leagueId]);

        return { success: true };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

