/**
 * Updates specific league settings.
 */
export async function updateLeagueSettings(leagueId: string, settings: { teams_locked?: boolean, join_locked?: boolean, name?: string }) {
    try {
        await verifyLeagueOwner(leagueId);

        if (settings.hasOwnProperty('teams_locked')) {
            // First time this might fail if column doesn't exist. I'll wrap it.
            try {
                await run(`UPDATE leagues SET teams_locked = ? WHERE id = ?`, [settings.teams_locked ? 1 : 0, leagueId]);
            } catch (e) {
                // If column missing, add it (simple migration)
                await run(`ALTER TABLE leagues ADD COLUMN teams_locked INTEGER DEFAULT 0`);
                await run(`UPDATE leagues SET teams_locked = ? WHERE id = ?`, [settings.teams_locked ? 1 : 0, leagueId]);
            }
        }

        if (settings.hasOwnProperty('join_locked')) {
            try {
                await run(`UPDATE leagues SET join_locked = ? WHERE id = ?`, [settings.join_locked ? 1 : 0, leagueId]);
            } catch (e) {
                await run(`ALTER TABLE leagues ADD COLUMN join_locked INTEGER DEFAULT 0`);
                await run(`UPDATE leagues SET join_locked = ? WHERE id = ?`, [settings.join_locked ? 1 : 0, leagueId]);
            }
        }

        if (settings.name) {
            await run(`UPDATE leagues SET name = ? WHERE id = ?`, [settings.name, leagueId]);
        }

        return { success: true };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

export async function deleteLeague(leagueId: string) {
    try {
        await verifyLeagueOwner(leagueId);

        // Delete all related data in sequence
        await run(`DELETE FROM race_results WHERE race_id IN (SELECT id FROM races WHERE league_id = ?)`, [leagueId]);
        await run(`DELETE FROM races WHERE league_id = ?`, [leagueId]);
        await run(`DELETE FROM drivers WHERE league_id = ?`, [leagueId]);
        await run(`DELETE FROM teams WHERE league_id = ?`, [leagueId]);
        await run(`DELETE FROM points_config WHERE league_id = ?`, [leagueId]);
        await run(`DELETE FROM leagues WHERE id = ?`, [leagueId]);

        return { success: true };
    } catch (error: any) {
        return { success: false, error: error.message };
    }
}

/**
 * Updates the user's password.
 */
export async function updateUserPassword(oldPassword: string, newPassword: string) {
    try {
        const session = await getServerSession(authOptions) as any;
        if (!session || !session.user || !session.user.id) throw new Error('Unauthorized.');

        const users = await query<any>('SELECT password_hash FROM users WHERE id = ?', [session.user.id]);
        if (users.length === 0) throw new Error('User not found.');

        const isValid = await bcrypt.compare(oldPassword, users[0].password_hash);
        if (!isValid) throw new Error('Das aktuelle Passwort ist nicht korrekt.');

        const salt = await bcrypt.genSalt(10);
        const hash = await bcrypt.hash(newPassword, salt);

        await run('UPDATE users SET password_hash = ? WHERE id = ?', [hash, session.user.id]);
        return { success: true };
    } catch (error: any) {
        console.error('Update Password Error:', error);
        return { success: false, error: error.message };
    }
}

